import{_ as s,o as n,c as e,ag as p}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Algorithms & Flowchart Symbols — Quick Reference","description":"","frontmatter":{},"headers":[],"relativePath":"quick-study/algorithms-flowchart.md","filePath":"quick-study/algorithms-flowchart.md"}'),l={name:"quick-study/algorithms-flowchart.md"};function i(t,a,r,c,o,d){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="algorithms-flowchart-symbols-—-quick-reference" tabindex="-1">Algorithms &amp; Flowchart Symbols — Quick Reference <a class="header-anchor" href="#algorithms-flowchart-symbols-—-quick-reference" aria-label="Permalink to &quot;Algorithms &amp; Flowchart Symbols — Quick Reference&quot;">​</a></h1><p>No prose. Symbols, pseudocode patterns, and algorithm structures only.</p><hr><h2 id="flowchart-symbols" tabindex="-1">Flowchart Symbols <a class="header-anchor" href="#flowchart-symbols" aria-label="Permalink to &quot;Flowchart Symbols&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symbol</th><th>Shape</th><th>Used for</th></tr></thead><tbody><tr><td><strong>Terminal</strong></td><td>Oval / rounded rectangle</td><td>START and END</td></tr><tr><td><strong>Process</strong></td><td>Rectangle</td><td>Assignment, calculation</td></tr><tr><td><strong>Decision</strong></td><td>Diamond</td><td>IF condition (Yes/No branches)</td></tr><tr><td><strong>Input/Output</strong></td><td>Parallelogram</td><td>Input from user or display output</td></tr><tr><td><strong>Connector</strong></td><td>Small circle</td><td>Connect flowchart across a page</td></tr><tr><td><strong>Arrow</strong></td><td>Line with arrowhead</td><td>Flow direction</td></tr><tr><td><strong>Subroutine</strong></td><td>Rectangle with double vertical lines</td><td>Call a procedure/function</td></tr></tbody></table><hr><h2 id="algorithm-properties" tabindex="-1">Algorithm Properties <a class="header-anchor" href="#algorithm-properties" aria-label="Permalink to &quot;Algorithm Properties&quot;">​</a></h2><p>A correct algorithm must be:</p><ul><li><strong>Finite</strong> — eventually terminates</li><li><strong>Definite</strong> — each step is precisely defined</li><li><strong>Effective</strong> — every step is doable</li><li><strong>Correct</strong> — produces the right output for all inputs</li></ul><hr><h2 id="pseudocode-conventions" tabindex="-1">Pseudocode Conventions <a class="header-anchor" href="#pseudocode-conventions" aria-label="Permalink to &quot;Pseudocode Conventions&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>READ name</span></span>
<span class="line"><span>WRITE &quot;Hello, &quot; + name</span></span>
<span class="line"><span>SET total = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>IF condition THEN</span></span>
<span class="line"><span>  statements</span></span>
<span class="line"><span>ELSE</span></span>
<span class="line"><span>  statements</span></span>
<span class="line"><span>ENDIF</span></span>
<span class="line"><span></span></span>
<span class="line"><span>FOR counter = start TO end</span></span>
<span class="line"><span>  statements</span></span>
<span class="line"><span>ENDFOR</span></span>
<span class="line"><span></span></span>
<span class="line"><span>WHILE condition DO</span></span>
<span class="line"><span>  statements</span></span>
<span class="line"><span>ENDWHILE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>REPEAT</span></span>
<span class="line"><span>  statements</span></span>
<span class="line"><span>UNTIL condition</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><hr><h2 id="sequential-algorithm-pattern" tabindex="-1">Sequential Algorithm Pattern <a class="header-anchor" href="#sequential-algorithm-pattern" aria-label="Permalink to &quot;Sequential Algorithm Pattern&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>START</span></span>
<span class="line"><span>  READ/CALCULATE inputs</span></span>
<span class="line"><span>  PROCESS (compute, assign)</span></span>
<span class="line"><span>  WRITE/DISPLAY outputs</span></span>
<span class="line"><span>END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>Example — Calculate VAT:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>START</span></span>
<span class="line"><span>  READ price</span></span>
<span class="line"><span>  SET vat = price × 0.15</span></span>
<span class="line"><span>  SET total = price + vat</span></span>
<span class="line"><span>  WRITE &quot;Total: R&quot; + total</span></span>
<span class="line"><span>END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><hr><h2 id="decision-algorithm-patterns" tabindex="-1">Decision Algorithm Patterns <a class="header-anchor" href="#decision-algorithm-patterns" aria-label="Permalink to &quot;Decision Algorithm Patterns&quot;">​</a></h2><h3 id="single-if" tabindex="-1">Single IF <a class="header-anchor" href="#single-if" aria-label="Permalink to &quot;Single IF&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IF mark &gt;= 50 THEN</span></span>
<span class="line"><span>  WRITE &quot;Pass&quot;</span></span>
<span class="line"><span>ENDIF</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="if-else" tabindex="-1">IF...ELSE <a class="header-anchor" href="#if-else" aria-label="Permalink to &quot;IF...ELSE&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IF mark &gt;= 50 THEN</span></span>
<span class="line"><span>  WRITE &quot;Pass&quot;</span></span>
<span class="line"><span>ELSE</span></span>
<span class="line"><span>  WRITE &quot;Fail&quot;</span></span>
<span class="line"><span>ENDIF</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="chained" tabindex="-1">Chained <a class="header-anchor" href="#chained" aria-label="Permalink to &quot;Chained&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IF mark &gt;= 80 THEN</span></span>
<span class="line"><span>  grade = &quot;A&quot;</span></span>
<span class="line"><span>ELSE IF mark &gt;= 70 THEN</span></span>
<span class="line"><span>  grade = &quot;B&quot;</span></span>
<span class="line"><span>ELSE IF mark &gt;= 50 THEN</span></span>
<span class="line"><span>  grade = &quot;C&quot;</span></span>
<span class="line"><span>ELSE</span></span>
<span class="line"><span>  grade = &quot;F&quot;</span></span>
<span class="line"><span>ENDIF</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><hr><h2 id="repetition-algorithm-patterns" tabindex="-1">Repetition Algorithm Patterns <a class="header-anchor" href="#repetition-algorithm-patterns" aria-label="Permalink to &quot;Repetition Algorithm Patterns&quot;">​</a></h2><h3 id="for-known-iterations" tabindex="-1">FOR (known iterations) <a class="header-anchor" href="#for-known-iterations" aria-label="Permalink to &quot;FOR (known iterations)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FOR i = 1 TO 10</span></span>
<span class="line"><span>  WRITE i</span></span>
<span class="line"><span>ENDFOR</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="while-may-not-run" tabindex="-1">WHILE (may not run) <a class="header-anchor" href="#while-may-not-run" aria-label="Permalink to &quot;WHILE (may not run)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET n = 1</span></span>
<span class="line"><span>WHILE n &lt;= 100</span></span>
<span class="line"><span>  WRITE n</span></span>
<span class="line"><span>  SET n = n × 2</span></span>
<span class="line"><span>ENDWHILE</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="repeat-until-runs-at-least-once" tabindex="-1">REPEAT...UNTIL (runs at least once) <a class="header-anchor" href="#repeat-until-runs-at-least-once" aria-label="Permalink to &quot;REPEAT...UNTIL (runs at least once)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>REPEAT</span></span>
<span class="line"><span>  READ choice</span></span>
<span class="line"><span>UNTIL choice = 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="common-algorithms-—-templates" tabindex="-1">Common Algorithms — Templates <a class="header-anchor" href="#common-algorithms-—-templates" aria-label="Permalink to &quot;Common Algorithms — Templates&quot;">​</a></h2><h3 id="sum-and-average" tabindex="-1">Sum and Average <a class="header-anchor" href="#sum-and-average" aria-label="Permalink to &quot;Sum and Average&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET sum = 0</span></span>
<span class="line"><span>FOR i = 1 TO n</span></span>
<span class="line"><span>  sum = sum + a[i]</span></span>
<span class="line"><span>ENDFOR</span></span>
<span class="line"><span>average = sum / n</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="find-maximum" tabindex="-1">Find Maximum <a class="header-anchor" href="#find-maximum" aria-label="Permalink to &quot;Find Maximum&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET max = a[1]</span></span>
<span class="line"><span>FOR i = 2 TO n</span></span>
<span class="line"><span>  IF a[i] &gt; max THEN</span></span>
<span class="line"><span>    max = a[i]</span></span>
<span class="line"><span>  ENDIF</span></span>
<span class="line"><span>ENDFOR</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="find-minimum" tabindex="-1">Find Minimum <a class="header-anchor" href="#find-minimum" aria-label="Permalink to &quot;Find Minimum&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET min = a[1]</span></span>
<span class="line"><span>FOR i = 2 TO n</span></span>
<span class="line"><span>  IF a[i] &lt; min THEN</span></span>
<span class="line"><span>    min = a[i]</span></span>
<span class="line"><span>  ENDIF</span></span>
<span class="line"><span>ENDFOR</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="linear-search" tabindex="-1">Linear Search <a class="header-anchor" href="#linear-search" aria-label="Permalink to &quot;Linear Search&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET found = FALSE</span></span>
<span class="line"><span>SET pos = 0</span></span>
<span class="line"><span>FOR i = 1 TO n</span></span>
<span class="line"><span>  IF a[i] = target THEN</span></span>
<span class="line"><span>    found = TRUE</span></span>
<span class="line"><span>    pos = i</span></span>
<span class="line"><span>  ENDIF</span></span>
<span class="line"><span>ENDFOR</span></span>
<span class="line"><span>IF found THEN</span></span>
<span class="line"><span>  WRITE &quot;Found at &quot; + pos</span></span>
<span class="line"><span>ELSE</span></span>
<span class="line"><span>  WRITE &quot;Not found&quot;</span></span>
<span class="line"><span>ENDIF</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="count-condition" tabindex="-1">Count Condition <a class="header-anchor" href="#count-condition" aria-label="Permalink to &quot;Count Condition&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET count = 0</span></span>
<span class="line"><span>FOR i = 1 TO n</span></span>
<span class="line"><span>  IF a[i] &gt; threshold THEN</span></span>
<span class="line"><span>    count = count + 1</span></span>
<span class="line"><span>  ENDIF</span></span>
<span class="line"><span>ENDFOR</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="bubble-sort-ascending" tabindex="-1">Bubble Sort (ascending) <a class="header-anchor" href="#bubble-sort-ascending" aria-label="Permalink to &quot;Bubble Sort (ascending)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FOR i = 1 TO n-1</span></span>
<span class="line"><span>  FOR j = 1 TO n-i</span></span>
<span class="line"><span>    IF a[j] &gt; a[j+1] THEN</span></span>
<span class="line"><span>      SWAP a[j] and a[j+1]</span></span>
<span class="line"><span>    ENDIF</span></span>
<span class="line"><span>  ENDFOR</span></span>
<span class="line"><span>ENDFOR</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="check-prime" tabindex="-1">Check Prime <a class="header-anchor" href="#check-prime" aria-label="Permalink to &quot;Check Prime&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET isPrime = TRUE</span></span>
<span class="line"><span>IF n &lt;= 1 THEN isPrime = FALSE</span></span>
<span class="line"><span>FOR i = 2 TO n-1</span></span>
<span class="line"><span>  IF n MOD i = 0 THEN</span></span>
<span class="line"><span>    isPrime = FALSE</span></span>
<span class="line"><span>  ENDIF</span></span>
<span class="line"><span>ENDFOR</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><hr><h2 id="tracing-an-algorithm" tabindex="-1">Tracing an Algorithm <a class="header-anchor" href="#tracing-an-algorithm" aria-label="Permalink to &quot;Tracing an Algorithm&quot;">​</a></h2><p>Given:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET x = 5</span></span>
<span class="line"><span>SET y = 2</span></span>
<span class="line"><span>WHILE y &lt; x</span></span>
<span class="line"><span>  SET x = x - 1</span></span>
<span class="line"><span>  SET y = y + 1</span></span>
<span class="line"><span>ENDWHILE</span></span>
<span class="line"><span>WRITE x, y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><table tabindex="0"><thead><tr><th>Step</th><th>x</th><th>y</th><th>Condition y &lt; x</th></tr></thead><tbody><tr><td>Start</td><td>5</td><td>2</td><td>2 &lt; 5 = TRUE</td></tr><tr><td>After iter 1</td><td>4</td><td>3</td><td>3 &lt; 4 = TRUE</td></tr><tr><td>After iter 2</td><td>3</td><td>4</td><td>4 &lt; 3 = FALSE → stop</td></tr></tbody></table><p>Output: x=3, y=4</p><hr><h2 id="delphi-equivalent-patterns" tabindex="-1">Delphi Equivalent Patterns <a class="header-anchor" href="#delphi-equivalent-patterns" aria-label="Permalink to &quot;Delphi Equivalent Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pseudocode</th><th>Delphi</th></tr></thead><tbody><tr><td><code>SET x = 5</code></td><td><code>x := 5;</code></td></tr><tr><td><code>READ name</code></td><td><code>sName := edtName.Text;</code></td></tr><tr><td><code>WRITE msg</code></td><td><code>redOutput.Lines.Add(msg);</code></td></tr><tr><td><code>IF x &gt; 0 THEN</code></td><td><code>IF x &gt; 0 THEN</code></td></tr><tr><td><code>FOR i = 1 TO n</code></td><td><code>FOR i := 1 TO n DO</code></td></tr><tr><td><code>WHILE x &lt; 10 DO</code></td><td><code>WHILE x &lt; 10 DO</code></td></tr><tr><td><code>REPEAT...UNTIL x = 0</code></td><td><code>REPEAT...UNTIL x = 0;</code></td></tr><tr><td><code>SWAP a, b</code></td><td><code>t := a; a := b; b := t;</code></td></tr></tbody></table>`,58)])])}const h=s(l,[["render",i]]);export{u as __pageData,h as default};
